// frontend/src/components/WeatherApp.jsx
import React, { useEffect, useState, useCallback } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";

// Default city
const ATL = { name: "Atlanta,US", lat: 33.749, lon: -84.388 };

// type guard
const isFiniteNum = (n) => typeof n === "number" && isFinite(n);

export default function WeatherApp() {
  const [place, setPlace] = useState(ATL);

  const [weather, setWeather] = useState({
    current: null,
    hourly: [],
    daily: [],
    summary: "",
  });
  const [daily16, setDaily16] = useState([]);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  // SEARCH: accept "City,Country" or {name,lat,lon}
  const handleSearch = (p) => {
    if (typeof p === "string") {
      setPlace({ name: p.trim() || ATL.name, lat: ATL.lat, lon: ATL.lon });
      return;
    }
    setPlace({
      name: p?.name || ATL.name,
      lat: isFiniteNum(p?.lat) ? p.lat : ATL.lat,
      lon: isFiniteNum(p?.lon) ? p.lon : ATL.lon,
    });
  };

  // fetch helper (uses CRA proxy -> relative paths)
  const fetchJSON = async (path, body) => {
    const res = await fetch(path, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
    if (!res.ok) throw new Error(`${res.status} ${res.statusText}`);
    return res.json();
  };

  const load = useCallback(async () => {
    setLoading(true);
    setErr("");
    try {
      // 1) current/hourly/daily + summary
      const data = await fetchJSON("/api/weather/current", {
        location: place.name,
        lat: place.lat,
        lon: place.lon,
      });
      const normalized = {
        current: data?.weather?.current ?? null,
        hourly: data?.weather?.hourly ?? [],
        daily: data?.weather?.daily ?? [],
        summary: data?.summary ?? "",
      };
      setWeather(normalized);

      // 2) extended 16-day
      const ext = await fetchJSON("/api/weather/forecast16", {
        location: place.name,
        days: 16,
      });
      setDaily16(ext?.weather?.daily ?? []);
    } catch (e) {
      console.error(e);
      setErr(e?.message || "Failed to load weather");
      setDaily16([]);
    } finally {
      setLoading(false);
    }
  }, [place.name, place.lat, place.lon]);

  useEffect(() => { load(); }, [load]);

  const now = weather.current || {};

  return (
    <div className="relative min-h-screen flex flex-col bg-neutral-50 text-neutral-900">
      {/* Background/overlay */}
      <WeatherOverlay condition={now?.weather} />

      {/* Top search */}
      <div className="z-10">
        <SearchSection
          defaultValue={place?.name || ""}
          onSearch={handleSearch}   // <-- fixed prop name
          loading={loading}
        />
      </div>

      {/* Status / errors */}
      <div className="z-10 mx-auto w-full max-w-5xl px-4">
        {loading && <div className="mt-2 text-sm text-neutral-600">Loading…</div>}
        {!loading && err && (
          <div className="mt-2 text-sm text-red-600">{err}</div>
        )}
      </div>

      {/* Header card */}
      <div className="z-10 mx-auto w-full max-w-5xl px-4 mt-3">
        <div className="rounded-2xl bg-black/30 backdrop-blur-md text-white p-4">
          <div className="text-sm opacity-90">Now in</div>
          <div className="text-xl font-semibold">{place?.name}</div>
          <div className="text-5xl font-bold mt-1">
            {now?.temp != null ? Math.round(now.temp) : "--"}°C
          </div>
          <div className="opacity-80">{now?.weather || "—"}</div>
          {weather.summary && (
            <div className="mt-3 opacity-90">{weather.summary}</div>
          )}
        </div>
      </div>

      {/* Radar */}
      <div className="z-10 mt-6 px-4">
        <div className="mx-auto w-full max-w-5xl">
          <Radar
            center={[place?.lat ?? ATL.lat, place?.lon ?? ATL.lon]}
            zoom={6}
            height={300}
            className="rounded-2xl overflow-hidden"
          />
        </div>
      </div>

      {/* Forecast tiles */}
      <div className="z-10 mt-6 px-4 pb-28">
        <div className="mx-auto w-full max-w-5xl">
          <Forecast
            hourly={weather.hourly}
            daily={weather.daily}
            daily16={daily16}
          />
        </div>
      </div>

      {/* Bottom nav */}
      <BottomBar active="home" />
    </div>
  );
}
